import { useState, useMemo, useCallback } from "react";
import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Switch } from "@/components/ui/switch";
import { Input } from "@/components/ui/input";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Pagination,
  PaginationContent,
  PaginationEllipsis,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from "@/components/ui/pagination";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useDeleteRestaurant, useBatchDeleteRestaurants, useToggleRestaurantVisibility, useBatchUpdateRestaurants } from "@/hooks/useAdmin";
import { useUserRole } from "@/hooks/useUserRole";
import { useBrands } from "@/hooks/useBrands";
import { RestaurantFormDialog } from "@/components/admin/RestaurantFormDialog";
import {
  Star, MapPin, Plus, Download, Trash2, Search, Ghost, Store, Users,
  Eye, EyeOff, Building2, Globe, BookOpen, Loader2, Camera, Coffee, Landmark,
  ChevronLeft, ChevronRight, Image, BarChart3, ExternalLink, Archive, ArchiveRestore,
} from "lucide-react";
import { exportRestaurantsToCSV } from "@/lib/exportUtils";
import { useToast } from "@/hooks/use-toast";

const PAGE_SIZE = 20;

interface AdminRestaurant {
  id: string;
  name: string;
  name_en: string | null;
  name_pt: string | null;
  address: string;
  phone: string | null;
  type: string | null;
  type_en: string | null;
  type_pt: string | null;
  image_url: string | null;
  rating: number | null;
  visible: boolean;
  archived: boolean;
  template: string | null;
  brand_id: string | null;
  is_chain: boolean | null;
  store_level: string | null;
  country: string | null;
  city: string | null;
  photo_story_zh: string | null;
  photo_story_en: string | null;
  created_at: string;
  updated_at: string;
  key_id: string | null;
  lat: number | null;
  lng: number | null;
}

const useAdminRestaurantsPaginated = (
  page: number,
  filters: {
    search: string;
    template: string;
    brandId: string;
    storyFilter: string;
    photoFilter: string;
    typeFilter: string;
    visibleFilter: string;
  }
) => {
  return useQuery({
    queryKey: [
      "admin-restaurants-paginated",
      page,
      filters.search,
      filters.template,
      filters.brandId,
      filters.storyFilter,
      filters.photoFilter,
      filters.typeFilter,
      filters.visibleFilter,
    ],
    queryFn: async () => {
      const { data, error } = await supabase.rpc("get_admin_restaurants_paginated", {
        p_offset: page * PAGE_SIZE,
        p_limit: PAGE_SIZE,
        p_search: filters.search || null,
        p_template: filters.template || null,
        p_brand_id: filters.brandId || null,
        p_story_filter: filters.storyFilter || null,
        p_photo_filter: filters.photoFilter || null,
        p_type_filter: filters.typeFilter || null,
        p_visible_filter: filters.visibleFilter || null,
      });
      if (error) throw error;
      const result = data as any;
      return {
        restaurants: (result?.data || []) as AdminRestaurant[],
        total: (result?.total || 0) as number,
      };
    },
    staleTime: 1000 * 60 * 2,
    placeholderData: (prev: any) => prev,
  });
};

const AdminRestaurants = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const { isSupervisor } = useUserRole();
  const { getLocalizedField } = useLocalizedContent();
  const deleteRestaurant = useDeleteRestaurant();
  const batchDeleteRestaurants = useBatchDeleteRestaurants();
  const batchUpdateRestaurants = useBatchUpdateRestaurants();
  const toggleRestaurantVisibility = useToggleRestaurantVisibility();
  const { data: brands } = useBrands();

  const [currentPage, setCurrentPage] = useState(0);
  const [selectedRestaurants, setSelectedRestaurants] = useState<string[]>([]);
  const [searchInput, setSearchInput] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [templateFilter, setTemplateFilter] = useState("all");
  const [brandFilter, setBrandFilter] = useState("all");
  const [storyFilter, setStoryFilter] = useState("all");
  const [photoFilter, setPhotoFilter] = useState("all");
  const [typeFilter, setTypeFilter] = useState("all");
  const [visibleFilter, setVisibleFilter] = useState("all");

  // Debounced search
  const [searchTimeout, setSearchTimeout] = useState<NodeJS.Timeout | null>(null);
  const handleSearchChange = (value: string) => {
    setSearchInput(value);
    if (searchTimeout) clearTimeout(searchTimeout);
    const timeout = setTimeout(() => {
      setSearchQuery(value);
      setCurrentPage(0);
    }, 400);
    setSearchTimeout(timeout);
  };

  const { data, isLoading, isFetching } = useAdminRestaurantsPaginated(currentPage, {
    search: searchQuery,
    template: templateFilter,
    brandId: brandFilter,
    storyFilter,
    photoFilter,
    typeFilter,
    visibleFilter,
  });

  const restaurants = data?.restaurants || [];
  const totalItems = data?.total || 0;
  const totalPages = Math.ceil(totalItems / PAGE_SIZE);

  // Merchant associations
  const { data: merchantAssignments } = useQuery({
    queryKey: ["merchant-restaurant-assignments"],
    queryFn: async () => {
      const { data: mrData, error: mrError } = await supabase
        .from("merchant_restaurants")
        .select("restaurant_id, user_id");
      if (mrError) throw mrError;
      const userIds = [...new Set(mrData.map(m => m.user_id))];
      if (userIds.length === 0) return [];
      const { data: profiles, error: pError } = await supabase
        .from("profiles")
        .select("id, display_name")
        .in("id", userIds);
      if (pError) throw pError;
      const profileMap = new Map(profiles.map(p => [p.id, p.display_name]));
      return mrData.map(m => ({
        ...m,
        display_name: profileMap.get(m.user_id) || m.user_id.slice(0, 8),
      }));
    },
    staleTime: 1000 * 60 * 5,
  });

  const merchantsByRestaurant = useMemo(() => {
    const map = new Map<string, Array<{ user_id: string; display_name: string }>>();
    merchantAssignments?.forEach((item) => {
      const list = map.get(item.restaurant_id) || [];
      list.push({ user_id: item.user_id, display_name: item.display_name });
      map.set(item.restaurant_id, list);
    });
    return map;
  }, [merchantAssignments]);

  // Toggling visibility with optimistic feedback
  const [togglingIds, setTogglingIds] = useState<Set<string>>(new Set());
  const handleToggleVisibility = useCallback(async (id: string, visible: boolean) => {
    setTogglingIds(prev => new Set(prev).add(id));
    toggleRestaurantVisibility.mutate(
      { restaurantId: id, visible },
      {
        onSettled: () => {
          setTogglingIds(prev => {
            const next = new Set(prev);
            next.delete(id);
            return next;
          });
          queryClient.invalidateQueries({ queryKey: ["admin-restaurants-paginated"] });
        },
      }
    );
  }, [toggleRestaurantVisibility, queryClient]);

  // Deleting with feedback
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const handleDelete = useCallback((id: string) => {
    setDeletingId(id);
    deleteRestaurant.mutate(id, {
      onSettled: () => {
        setDeletingId(null);
        queryClient.invalidateQueries({ queryKey: ["admin-restaurants-paginated"] });
      },
    });
  }, [deleteRestaurant, queryClient]);

  const toggleSelectRestaurant = (id: string) => {
    setSelectedRestaurants(prev =>
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const toggleSelectAll = () => {
    if (selectedRestaurants.length === restaurants.length && restaurants.length > 0) {
      setSelectedRestaurants([]);
    } else {
      setSelectedRestaurants(restaurants.map(r => r.id));
    }
  };

  const handleBatchDelete = () => {
    if (selectedRestaurants.length === 0) return;
    batchDeleteRestaurants.mutate(selectedRestaurants, {
      onSettled: () => {
        setSelectedRestaurants([]);
        queryClient.invalidateQueries({ queryKey: ["admin-restaurants-paginated"] });
      },
    });
  };

  const handleExport = async () => {
    toast({ title: "导出中...", description: "正在获取所有数据" });
    // For export, fetch all using the old method
    const pageSize = 1000;
    let allData: any[] = [];
    let from = 0;
    let hasMore = true;
    while (hasMore) {
      const { data, error } = await supabase
        .from("restaurants")
        .select("id, name, name_en, name_pt, address, phone, type, type_en, type_pt, rating, visible, template, country, city, created_at")
        .order("rating", { ascending: false })
        .range(from, from + pageSize - 1);
      if (error) break;
      allData = allData.concat(data || []);
      hasMore = (data?.length || 0) === pageSize;
      from += pageSize;
    }
    if (allData.length > 0) {
      exportRestaurantsToCSV(allData);
      toast({ title: "导出成功", description: `共 ${allData.length} 条` });
    }
  };

  const goToPage = (page: number) => {
    setCurrentPage(Math.max(0, Math.min(page, totalPages - 1)));
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const getTemplateIcon = (template: string | null) => {
    switch (template) {
      case 'ghost': return <Ghost className="h-3.5 w-3.5 text-primary" />;
      case 'landmark': return <Landmark className="h-3.5 w-3.5 text-amber-600" />;
      default: return <Store className="h-3.5 w-3.5 text-muted-foreground" />;
    }
  };

  const getTemplateLabel = (template: string | null) => {
    switch (template) {
      case 'ghost': return '外壳';
      case 'landmark': return '名胜';
      default: return '标准';
    }
  };

  const startIndex = totalItems === 0 ? 0 : currentPage * PAGE_SIZE + 1;
  const endIndex = Math.min((currentPage + 1) * PAGE_SIZE, totalItems);

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-3">
        <div>
          <h1 className="text-2xl font-bold">{t("admin.restaurantManagement")}</h1>
          <p className="text-sm text-muted-foreground">
            共 {totalItems.toLocaleString()} 家商店
            {isFetching && !isLoading && <Loader2 className="inline ml-2 h-3.5 w-3.5 animate-spin" />}
          </p>
        </div>
        <div className="flex gap-2 flex-wrap">
          <Link to="/admin/discover-restaurants">
            <Button variant="outline" size="sm">
              <Globe className="mr-1.5 h-4 w-4" />
              搜索全球
            </Button>
          </Link>
          <Button variant="outline" size="sm" onClick={handleExport}>
            <Download className="mr-1.5 h-4 w-4" />
            导出
          </Button>
          <RestaurantFormDialog
            trigger={
              <Button size="sm">
                <Plus className="mr-1.5 h-4 w-4" />
                {t("admin.addRestaurant")}
              </Button>
            }
          />
        </div>
      </div>

      {/* Filters */}
      <div className="flex gap-2 flex-wrap items-center bg-muted/30 rounded-lg p-3">
        <div className="flex-1 min-w-[200px] max-w-[320px]">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="搜索名称、地址、城市..."
              value={searchInput}
              onChange={(e) => handleSearchChange(e.target.value)}
              className="pl-8 h-9"
            />
          </div>
        </div>
        <Select value={templateFilter} onValueChange={(v) => { setTemplateFilter(v); setCurrentPage(0); }}>
          <SelectTrigger className="w-[120px] h-9">
            <SelectValue placeholder="模板" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">全部模板</SelectItem>
            <SelectItem value="default">标准</SelectItem>
            <SelectItem value="ghost">外壳</SelectItem>
            <SelectItem value="landmark">名胜</SelectItem>
          </SelectContent>
        </Select>
        <Select value={visibleFilter} onValueChange={(v) => { setVisibleFilter(v); setCurrentPage(0); }}>
          <SelectTrigger className="w-[120px] h-9">
            <SelectValue placeholder="可见性" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">全部状态</SelectItem>
            <SelectItem value="visible">已显示</SelectItem>
            <SelectItem value="hidden">已隐藏</SelectItem>
            <SelectItem value="archived">已归档</SelectItem>
          </SelectContent>
        </Select>
        <Select value={storyFilter} onValueChange={(v) => { setStoryFilter(v); setCurrentPage(0); }}>
          <SelectTrigger className="w-[120px] h-9">
            <SelectValue placeholder="故事" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">全部故事</SelectItem>
            <SelectItem value="with">有故事</SelectItem>
            <SelectItem value="without">无故事</SelectItem>
          </SelectContent>
        </Select>
        <Select value={photoFilter} onValueChange={(v) => { setPhotoFilter(v); setCurrentPage(0); }}>
          <SelectTrigger className="w-[120px] h-9">
            <SelectValue placeholder="照片" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">全部照片</SelectItem>
            <SelectItem value="with">有照片</SelectItem>
            <SelectItem value="without">无照片</SelectItem>
          </SelectContent>
        </Select>
        {brands && brands.length > 0 && (
          <Select value={brandFilter} onValueChange={(v) => { setBrandFilter(v); setCurrentPage(0); }}>
            <SelectTrigger className="w-[140px] h-9">
              <SelectValue placeholder="品牌" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">全部品牌</SelectItem>
              <SelectItem value="none">无品牌</SelectItem>
              {brands.filter(b => b.id?.trim()).map((brand) => (
                <SelectItem key={brand.id} value={brand.id}>
                  {getLocalizedField(brand, "name")}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        )}
      </div>

      {/* Batch Operations */}
      {!isSupervisor && selectedRestaurants.length > 0 && (
        <div className="flex items-center gap-3 bg-primary/5 border border-primary/20 rounded-lg px-4 py-2.5">
          <span className="text-sm font-medium">已选 {selectedRestaurants.length} 项</span>
          <div className="flex gap-2 flex-wrap">
            <Button
              variant="outline" size="sm"
              onClick={() => {
                batchUpdateRestaurants.mutate(
                  { ids: selectedRestaurants, updates: { visible: true } },
                  { onSettled: () => {
                    setSelectedRestaurants([]);
                    queryClient.invalidateQueries({ queryKey: ["admin-restaurants-paginated"] });
                  }}
                );
              }}
            >
              <Eye className="mr-1.5 h-3.5 w-3.5" />
              显示
            </Button>
            <Button
              variant="outline" size="sm"
              onClick={() => {
                batchUpdateRestaurants.mutate(
                  { ids: selectedRestaurants, updates: { visible: false } },
                  { onSettled: () => {
                    setSelectedRestaurants([]);
                    queryClient.invalidateQueries({ queryKey: ["admin-restaurants-paginated"] });
                  }}
                );
              }}
            >
              <EyeOff className="mr-1.5 h-3.5 w-3.5" />
              隐藏
            </Button>
            <Button
              variant="outline" size="sm"
              onClick={() => {
                batchUpdateRestaurants.mutate(
                  { ids: selectedRestaurants, updates: { archived: true, visible: false } },
                  { onSettled: () => {
                    setSelectedRestaurants([]);
                    queryClient.invalidateQueries({ queryKey: ["admin-restaurants-paginated"] });
                  }}
                );
              }}
            >
              <Archive className="mr-1.5 h-3.5 w-3.5" />
              归档
            </Button>
            <Button
              variant="outline" size="sm"
              onClick={() => {
                batchUpdateRestaurants.mutate(
                  { ids: selectedRestaurants, updates: { archived: false, visible: true } },
                  { onSettled: () => {
                    setSelectedRestaurants([]);
                    queryClient.invalidateQueries({ queryKey: ["admin-restaurants-paginated"] });
                  }}
                );
              }}
            >
              <ArchiveRestore className="mr-1.5 h-3.5 w-3.5" />
              取消归档
            </Button>
            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button variant="destructive" size="sm">
                  <Trash2 className="mr-1.5 h-3.5 w-3.5" />
                  删除
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>确认批量删除</AlertDialogTitle>
                  <AlertDialogDescription>
                    将删除 {selectedRestaurants.length} 家商店，此操作不可撤销。
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>取消</AlertDialogCancel>
                  <AlertDialogAction onClick={handleBatchDelete}>确认删除</AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
            <Button variant="ghost" size="sm" onClick={() => setSelectedRestaurants([])}>
              取消选择
            </Button>
          </div>
        </div>
      )}

      {/* Table */}
      <div className="rounded-lg border bg-card overflow-hidden">
        <Table className="table-fixed w-full">
          <TableHeader>
            <TableRow className="hover:bg-transparent">
              {!isSupervisor && (
                <TableHead className="w-8">
                  <Checkbox
                    checked={selectedRestaurants.length === restaurants.length && restaurants.length > 0}
                    onCheckedChange={toggleSelectAll}
                  />
                </TableHead>
              )}
              <TableHead className="w-10"></TableHead>
              <TableHead className="w-[30%]">名称</TableHead>
              <TableHead className="hidden lg:table-cell">地址</TableHead>
              <TableHead className="hidden xl:table-cell w-20">类型</TableHead>
              <TableHead className="w-14 text-center">评分</TableHead>
              <TableHead className="hidden xl:table-cell w-16">模板</TableHead>
              <TableHead className="hidden lg:table-cell w-20">负责人</TableHead>
              <TableHead className="w-14 text-center">显示</TableHead>
              <TableHead className="w-32 text-right">操作</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {isLoading ? (
              Array.from({ length: 10 }).map((_, i) => (
                <TableRow key={i}>
                  {!isSupervisor && <TableCell><Skeleton className="h-4 w-4" /></TableCell>}
                  <TableCell><Skeleton className="h-9 w-9 rounded" /></TableCell>
                  <TableCell><Skeleton className="h-4 w-32" /></TableCell>
                  <TableCell className="hidden lg:table-cell"><Skeleton className="h-4 w-40" /></TableCell>
                  <TableCell className="hidden md:table-cell"><Skeleton className="h-4 w-16" /></TableCell>
                  <TableCell><Skeleton className="h-4 w-8 mx-auto" /></TableCell>
                  <TableCell className="hidden md:table-cell"><Skeleton className="h-4 w-12" /></TableCell>
                  <TableCell className="hidden lg:table-cell"><Skeleton className="h-4 w-16" /></TableCell>
                  <TableCell><Skeleton className="h-4 w-8 mx-auto" /></TableCell>
                  <TableCell><Skeleton className="h-4 w-20 ml-auto" /></TableCell>
                </TableRow>
              ))
            ) : restaurants.length === 0 ? (
              <TableRow>
                <TableCell colSpan={10} className="text-center py-12 text-muted-foreground">
                  没有找到匹配的商店
                </TableCell>
              </TableRow>
            ) : (
              restaurants.map((restaurant) => {
                const merchants = merchantsByRestaurant.get(restaurant.id);
                const hasStory = !!(restaurant.photo_story_zh || restaurant.photo_story_en);
                const hasPhoto = !!(restaurant.image_url && !restaurant.image_url.includes('placeholder'));
                const displayName = getLocalizedField(restaurant, "name");
                const displayType = getLocalizedField(restaurant, "type");

                return (
                  <TableRow key={restaurant.id} className="group">
                    {!isSupervisor && (
                      <TableCell>
                        <Checkbox
                          checked={selectedRestaurants.includes(restaurant.id)}
                          onCheckedChange={() => toggleSelectRestaurant(restaurant.id)}
                        />
                      </TableCell>
                    )}
                    <TableCell className="p-2">
                      {hasPhoto ? (
                        <img
                          src={restaurant.image_url!}
                          alt=""
                          className="h-9 w-9 rounded object-cover"
                          loading="lazy"
                        />
                      ) : (
                        <div className="h-9 w-9 rounded bg-muted flex items-center justify-center">
                          <Image className="h-4 w-4 text-muted-foreground/50" />
                        </div>
                      )}
                    </TableCell>
                    <TableCell className="overflow-hidden">
                      <div className="min-w-0">
                        <div className="font-medium truncate" title={String(displayName)}>
                          {displayName}
                        </div>
                        <div className="flex items-center gap-1.5 mt-0.5">
                          {restaurant.archived && (
                            <Badge variant="outline" className="text-[10px] px-1 py-0 border-orange-300 text-orange-600">
                              <Archive className="h-2.5 w-2.5 mr-0.5" />
                              已归档
                            </Badge>
                          )}
                          {restaurant.city && (
                            <span className="text-xs text-muted-foreground truncate">
                              {restaurant.city}
                            </span>
                          )}
                          {restaurant.country && (
                            <span className="text-xs text-muted-foreground/60 flex-shrink-0">
                              {restaurant.country}
                            </span>
                          )}
                          {hasStory && (
                            <BookOpen className="h-3 w-3 text-green-500 flex-shrink-0" />
                          )}
                        </div>
                      </div>
                    </TableCell>
                    <TableCell className="hidden lg:table-cell overflow-hidden">
                      <span className="text-sm text-muted-foreground truncate block" title={restaurant.address}>
                        {restaurant.address}
                      </span>
                    </TableCell>
                    <TableCell className="hidden xl:table-cell overflow-hidden">
                      <span className="text-xs text-muted-foreground truncate block">
                        {Array.isArray(displayType) ? displayType[0] : displayType}
                      </span>
                    </TableCell>
                    <TableCell className="text-center">
                      {restaurant.rating ? (
                        <span className="inline-flex items-center gap-0.5 text-sm">
                          <Star className="h-3 w-3 fill-amber-400 text-amber-400" />
                          {restaurant.rating}
                        </span>
                      ) : (
                        <span className="text-xs text-muted-foreground/40">-</span>
                      )}
                    </TableCell>
                    <TableCell className="hidden xl:table-cell overflow-hidden">
                      <span className="inline-flex items-center gap-1 text-xs truncate">
                        {getTemplateIcon(restaurant.template)}
                        {getTemplateLabel(restaurant.template)}
                      </span>
                    </TableCell>
                    <TableCell className="hidden lg:table-cell">
                      {merchants && merchants.length > 0 ? (
                        <div className="flex items-center gap-1">
                          <Users className="h-3 w-3 text-muted-foreground flex-shrink-0" />
                          <span className="text-xs truncate max-w-[80px]">{merchants[0].display_name}</span>
                          {merchants.length > 1 && (
                            <span className="text-xs text-muted-foreground">+{merchants.length - 1}</span>
                          )}
                        </div>
                      ) : (
                        <span className="text-xs text-muted-foreground/40">-</span>
                      )}
                    </TableCell>
                    <TableCell className="text-center">
                      <Switch
                        checked={restaurant.visible ?? true}
                        disabled={togglingIds.has(restaurant.id)}
                        onCheckedChange={(checked) => handleToggleVisibility(restaurant.id, checked)}
                        className="scale-75"
                      />
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex items-center justify-end gap-1 flex-nowrap opacity-60 group-hover:opacity-100 transition-opacity">
                        <Button variant="ghost" size="icon" className="h-7 w-7" asChild>
                          <Link to={`/restaurant/${restaurant.id}`} state={{ from: "admin" }} title="查看">
                            <ExternalLink className="h-3.5 w-3.5" />
                          </Link>
                        </Button>
                        <Button variant="ghost" size="icon" className="h-7 w-7" asChild>
                          <Link to={`/admin/restaurant-stats/${restaurant.id}`} title="数据">
                            <BarChart3 className="h-3.5 w-3.5" />
                          </Link>
                        </Button>
                        <RestaurantFormDialog
                          restaurant={restaurant as any}
                          trigger={
                            <Button variant="ghost" size="sm" className="h-7 px-2 text-xs">
                              编辑
                            </Button>
                          }
                        />
                        {!isSupervisor && (
                          <AlertDialog>
                            <AlertDialogTrigger asChild>
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-7 w-7 text-destructive hover:text-destructive"
                                disabled={deletingId === restaurant.id}
                              >
                                {deletingId === restaurant.id ? (
                                  <Loader2 className="h-3.5 w-3.5 animate-spin" />
                                ) : (
                                  <Trash2 className="h-3.5 w-3.5" />
                                )}
                              </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                              <AlertDialogHeader>
                                <AlertDialogTitle>确认删除</AlertDialogTitle>
                                <AlertDialogDescription>
                                  确定要删除「{displayName}」吗？此操作不可撤销。
                                </AlertDialogDescription>
                              </AlertDialogHeader>
                              <AlertDialogFooter>
                                <AlertDialogCancel>取消</AlertDialogCancel>
                                <AlertDialogAction onClick={() => handleDelete(restaurant.id)}>
                                  删除
                                </AlertDialogAction>
                              </AlertDialogFooter>
                            </AlertDialogContent>
                          </AlertDialog>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                );
              })
            )}
          </TableBody>
        </Table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between">
          <span className="text-sm text-muted-foreground">
            {startIndex}-{endIndex} / {totalItems.toLocaleString()}
          </span>
          <Pagination>
            <PaginationContent>
              <PaginationItem>
                <PaginationPrevious
                  onClick={() => goToPage(currentPage - 1)}
                  className={currentPage === 0 ? "pointer-events-none opacity-50" : "cursor-pointer"}
                />
              </PaginationItem>
              {Array.from({ length: totalPages }, (_, i) => i).map((page) => {
                if (
                  page === 0 ||
                  page === totalPages - 1 ||
                  (page >= currentPage - 1 && page <= currentPage + 1)
                ) {
                  return (
                    <PaginationItem key={page}>
                      <PaginationLink
                        onClick={() => goToPage(page)}
                        isActive={currentPage === page}
                        className="cursor-pointer"
                      >
                        {page + 1}
                      </PaginationLink>
                    </PaginationItem>
                  );
                }
                if (page === currentPage - 2 || page === currentPage + 2) {
                  return (
                    <PaginationItem key={page}>
                      <PaginationEllipsis />
                    </PaginationItem>
                  );
                }
                return null;
              })}
              <PaginationItem>
                <PaginationNext
                  onClick={() => goToPage(currentPage + 1)}
                  className={currentPage >= totalPages - 1 ? "pointer-events-none opacity-50" : "cursor-pointer"}
                />
              </PaginationItem>
            </PaginationContent>
          </Pagination>
        </div>
      )}
    </div>
  );
};

export default AdminRestaurants;
